  1→import React, { useState, useRef, useCallback } from 'react';
  2→import { Sparkles, TrendingUp, Target, Award, MousePointerClick, ArrowRight, ScanLine, Code2, Globe2, Fuel, Zap, Star, Check, Search, Bot, BrainCircuit, Database, Share2, Layers, Infinity, Radio, Globe, Droplet, Loader2, Gift, Shield, UserCheck, GraduationCap, BadgeCheck } from 'lucide-react';
  3→import { User } from '../types';
  4→import ScoreRing from '../components/ScoreRing';
  5→import { auditAnswerFirst, AnswerFirstAuditResult } from '../services/answer-first-audit';
  6→
  7→interface HomeProps {
  8→  onNavigate: (view: 'analyze' | 'login' | 'recharge' | 'directory') => void;
  9→  user: User | null;
 10→  onDirectRecharge?: (packId: number) => void;
 11→}
 12→
 13→const Home: React.FC<HomeProps> = ({ onNavigate, user, onDirectRecharge }) => {
 14→
 15→  // ── Score Gratuit State ──
 16→  const [brandName, setBrandName] = useState('');
 17→  const [siteUrl, setSiteUrl] = useState('');
 18→  const [isAnalyzing, setIsAnalyzing] = useState(false);
 19→  const [auditResult, setAuditResult] = useState<AnswerFirstAuditResult | null>(null);
 20→  const [auditError, setAuditError] = useState<string | null>(null);
 21→  const resultsRef = useRef<HTMLDivElement>(null);
 22→
 23→  // Derive E-E-A-T pillar scores from the 6 audit categories
 24→  const eeatPillars = auditResult ? [
 25→    { label: 'Experience', icon: <UserCheck size={16} />, score: Math.round((auditResult.categories.contentFreshness.score + auditResult.categories.answerFirst.score) / 2) },
 26→    { label: 'Expertise', icon: <GraduationCap size={16} />, score: Math.round((auditResult.categories.faqStructure.score + auditResult.categories.semanticHtml.score) / 2) },
 27→    { label: 'Authority', icon: <BadgeCheck size={16} />, score: Math.round((auditResult.categories.schemaOrg.score + auditResult.categories.metaOptimization.score) / 2) },
 28→    { label: 'Trust', icon: <Shield size={16} />, score: Math.round((auditResult.categories.metaOptimization.score + auditResult.categories.schemaOrg.score + auditResult.categories.answerFirst.score) / 3) },
 29→  ] : [];
 30→
 31→  const handleFreeAudit = useCallback(async () => {
 32→    if (!brandName.trim() || !siteUrl.trim()) {
 33→      setAuditError('Veuillez remplir les deux champs.');
 34→      return;
 35→    }
 36→    // Basic URL validation
 37→    let finalUrl = siteUrl.trim();
 38→    if (!/^https?:\/\//i.test(finalUrl)) {
 39→      finalUrl = 'https://' + finalUrl;
 40→    }
 41→    try {
 42→      new URL(finalUrl);
 43→    } catch {
 44→      setAuditError('URL invalide. Exemple : https://www.example.com');
 45→      return;
 46→    }
 47→
 48→    setAuditError(null);
 49→    setAuditResult(null);
 50→    setIsAnalyzing(true);
 51→
 52→    try {
 53→      const result = await auditAnswerFirst(finalUrl, brandName.trim());
 54→      setAuditResult(result);
 55→      // Scroll to results after a small delay for render
 56→      setTimeout(() => {
 57→        resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
 58→      }, 150);
 59→    } catch (err) {
 60→      setAuditError('Une erreur est survenue lors de l\'analyse. Veuillez reessayer.');
 61→    } finally {
 62→      setIsAnalyzing(false);
 63→    }
 64→  }, [brandName, siteUrl]);
 65→
 66→  const getScoreLabel = (score: number): string => {
 67→    if (score >= 80) return 'Excellent';
 68→    if (score >= 60) return 'Bon';
 69→    if (score >= 40) return 'Moyen';
 70→    if (score >= 20) return 'Faible';
 71→    return 'Critique';
 72→  };
 73→
 74→  const getScoreColor = (score: number): string => {
 75→    if (score >= 80) return 'text-purple-400';
 76→    if (score >= 60) return 'text-violet-400';
 77→    if (score >= 40) return 'text-amber-400';
 78→    return 'text-red-400';
 79→  };
 80→
 81→  const getBarColor = (score: number): string => {
 82→    if (score >= 80) return 'bg-purple-500';
 83→    if (score >= 60) return 'bg-violet-500';
 84→    if (score >= 40) return 'bg-amber-500';
 85→    return 'bg-red-500';
 86→  };
 87→
 88→  const handleStartAnalysis = () => {
 89→    if (user) {
 90→      onNavigate('analyze');
 91→    } else {
 92→      onNavigate('login');
 93→    }
 94→  };
 95→
 96→  const handleSelectPlan = (packId: number) => {
 97→    if (user) {
 98→      if (onDirectRecharge) {
 99→        onDirectRecharge(packId);
100→      } else {
101→        onNavigate('recharge');
102→      }
103→    } else {
104→      onNavigate('login');
105→    }
106→  };
107→
108→  const plans = [
109→    {
110→      id: 1,
111→      name: "Le Jerrican",
112→      credits: 50,
113→      price: 15,
114→      icon: <Droplet size={24} />,
115→      popular: false,
116→      features: ["Id\u00e9al pour tester", "1 Audit complet", "Valable 1 an"]
117→    },
118→    {
119→      id: 2,
120→      name: "La Pompe",
121→      credits: 200,
122→      price: 49,
123→      icon: <Fuel size={24} />,
124→      popular: true,
125→      features: ["Pour optimiser s\u00e9rieusement", "Support prioritaire", "+10% Bonus offert"]
126→    },
127→    {
128→      id: 3,
129→      name: "La Citerne",
130→      credits: 1000,
131→      price: 199,
132→      icon: <Database size={24} />,
133→      popular: false,
134→      features: ["Usage intensif / Agence", "Acc\u00e8s API Beta", "+20% Bonus offert"]
135→    }
136→  ];
137→
138→  return (
139→    <div className="w-full px-6 pt-16 pb-32 overflow-hidden">
140→
141→      {/* ── HERO SECTION ── */}
142→      <div className="text-center mb-32 relative">
143→        {/* Ambient glow */}
144→        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[700px] h-[500px] bg-purple-600/8 blur-[150px] rounded-full -z-10 pointer-events-none"></div>
145→
146→        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-gray-400 text-xs font-medium tracking-wide uppercase mb-10">
147→          <Sparkles size={12} className="text-purple-400" />
148→          <span>Plateforme AEO / GEO</span>
149→        </div>
150→
151→        <h1 className="text-5xl sm:text-6xl md:text-[5.5rem] font-sans font-bold tracking-tight text-white leading-[1.05] mb-8">
152→          Faites-vous citer{' '}
153→          <br className="hidden md:block" />
154→          par les <span className="gradient-text">IA G{'\u00e9'}n{'\u00e9'}ratives</span>
155→        </h1>
156→
157→        <p className="text-lg md:text-xl text-gray-500 max-w-2xl mx-auto leading-relaxed mb-12 font-light">
158→          La premi{'\u00e8'}re plateforme d'optimisation AEO. Analysez et influencez la fa{'\u00e7'}on dont ChatGPT, Claude, Gemini et AI Overviews per{'\u00e7'}oivent votre marque.
159→        </p>
160→
161→        <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
162→          <button onClick={handleStartAnalysis} className="btn-gradient text-base px-8 py-3.5 flex items-center gap-2.5 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30">
163→            Lancer un Audit Gratuit <ArrowRight size={18} />
164→          </button>
165→          <button onClick={() => onNavigate('directory')} className="px-8 py-3.5 rounded-full border border-white/[0.1] text-gray-300 text-base font-medium hover:bg-white/[0.04] hover:border-white/[0.15] transition-all">
166→            Explorer l'Annuaire
167→          </button>
168→        </div>
169→      </div>
170→
171→      {/* ── SCORE GRATUIT DE VISIBILITE IA ── */}
172→      <div className="mb-32 relative" id="score-gratuit">
173→        {/* Ambient glow */}
174→        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[600px] bg-purple-600/[0.06] blur-[180px] rounded-full -z-10 pointer-events-none"></div>
175→
176→        {/* Section header */}
177→        <div className="text-center mb-12">
178→          {/* GRATUIT Banner */}
179→          <div className="inline-flex items-center gap-2 px-5 py-2 rounded-full bg-gradient-to-r from-purple-500/20 to-violet-600/20 border border-purple-500/30 text-white text-sm font-bold tracking-wide uppercase mb-8 shadow-lg shadow-purple-600/10">
180→            <Gift size={16} className="text-purple-400" />
181→            <span>100% GRATUIT</span>
182→            <span className="text-purple-400">&mdash;</span>
183→            <span className="text-purple-300">Sans inscription</span>
184→          </div>
185→
186→          <h2 className="text-3xl md:text-5xl font-sans font-bold text-white tracking-tight mb-5">
187→            Votre Score de <span className="gradient-text">Visibilit{'\u00e9'} IA</span>
188→          </h2>
189→          <p className="text-gray-500 max-w-2xl mx-auto text-lg">
190→            D{'\u00e9'}couvrez en 30 secondes comment les IA g{'\u00e9'}n{'\u00e9'}ratives per{'\u00e7'}oivent votre marque. Aucun compte requis.
191→          </p>
192→        </div>
193→
194→        {/* Form + Results Container */}
195→        <div className="max-w-3xl mx-auto">
196→          {/* Form Card */}
197→          <div className="ninja-card p-8 md:p-10 relative overflow-hidden">
198→            {/* Decorative gradient line at top */}
199→            <div className="absolute top-0 left-0 right-0 h-[2px] bg-gradient-to-r from-transparent via-purple-500 to-transparent"></div>
200→
201→            <form
