223→                    placeholder="Ex: https://www.citedby.ai"
224→                    className="w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-white placeholder-gray-600 outline-none transition-all focus:border-purple-500/50 focus:bg-white/[0.06] focus:shadow-[0_0_20px_rgba(168,85,247,0.08)]"
225→                    disabled={isAnalyzing}
226→                  />
227→                </div>
228→              </div>
229→
230→              {auditError && (
231→                <p className="text-sm text-red-400 bg-red-500/10 border border-red-500/20 rounded-xl px-4 py-2.5">{auditError}</p>
232→              )}
233→
234→              <button
235→                type="submit"
236→                disabled={isAnalyzing}
237→                className="w-full btn-gradient py-4 text-base font-bold flex items-center justify-center gap-3 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30 disabled:opacity-60 disabled:cursor-not-allowed transition-all"
238→              >
239→                {isAnalyzing ? (
240→                  <>
241→                    <Loader2 size={20} className="animate-spin" />
242→                    Analyse en cours...
243→                  </>
244→                ) : (
245→                  <>
246→                    <Sparkles size={20} />
