248→                  </>
249→                )}
250→              </button>
251→
252→              <p className="text-center text-xs text-gray-600">
253→                Aucune carte bancaire requise. 0 GTO Gas consomm{'\u00e9'}. R{'\u00e9'}sultat instantan{'\u00e9'}.
254→              </p>
255→            </form>
256→          </div>
257→
258→          {/* Loading Animation */}
259→          {isAnalyzing && (
260→            <div className="mt-8 ninja-card p-10 flex flex-col items-center justify-center gap-5">
261→              <div className="relative">
262→                <div className="w-24 h-24 rounded-full border-4 border-white/[0.06]"></div>
